// Estrae testo pulito dal body HTML dell'email
const htmlBody = $input.first().json.body?.content || '';
const subject = $input.first().json.subject || '';
const fromEmail = $input.first().json.from?.emailAddress?.address || '';
const fromName = $input.first().json.from?.emailAddress?.name || '';
const receivedAt = $input.first().json.receivedDateTime || '';
const messageId = $input.first().json.id || '';
const conversationId = $input.first().json.conversationId || '';

// Rimuovi HTML tags per avere testo pulito
let plainText = htmlBody
  .replace(/<style[^>]*>.*?<\/style>/gsi, '')
  .replace(/<script[^>]*>.*?<\/script>/gsi, '')
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/p>/gi, '\n\n')
  .replace(/<\/div>/gi, '\n')
  .replace(/<[^>]+>/g, '')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&#39;/g, "'")
  .replace(/&quot;/g, '"')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

// Tronca a 3000 caratteri per non superare il context window
if (plainText.length > 3000) {
  plainText = plainText.substring(0, 3000) + '\n[...email troncata]';
}

// Classifica tipo di richiesta
const textLower = (subject + ' ' + plainText).toLowerCase();
let categoria = 'generale';

if (textLower.match(/disponibil|prenotare|prenota|booking|reservation/)) {
  categoria = 'disponibilita';
} else if (textLower.match(/prezz[oi]|cost[oi]|tariffa|listino|quot/)) {
  categoria = 'prezzi';
} else if (textLower.match(/check.?in|check.?out|arriv|orar|chiav/)) {
  categoria = 'checkin';
} else if (textLower.match(/cancel|rimborso|annulla|disdett/)) {
  categoria = 'cancellazione';
} else if (textLower.match(/animali|cane|gatto|pet|dog/)) {
  categoria = 'animali';
} else if (textLower.match(/bianche|lenzuol|asciugaman|pulizia|pulizie/)) {
  categoria = 'servizi_extra';
} else if (textLower.match(/propon|proprietar|affiliaz|collabor/)) {
  categoria = 'proposta_immobile';
} else if (textLower.match(/recla|problema|guast|rott/)) {
  categoria = 'reclamo';
}

return [{
  json: {
    messageId,
    conversationId,
    fromEmail,
    fromName,
    subject,
    plainText,
    htmlBody,
    receivedAt,
    categoria,
  }
}];

const claudeResponse = $input.first().json;
const emailData = $('Parsa Email').first().json;

// Estrai la risposta dal formato API Claude
let rispostaText = '';
if (claudeResponse.content && claudeResponse.content.length > 0) {
  rispostaText = claudeResponse.content[0].text || '';
} else {
  rispostaText = 'Errore: risposta Claude vuota. Controllare i log.';
}

// Estrai eventuale oggetto dalla risposta (se Claude lo include)
let oggettoRisposta = 'Re: ' + emailData.subject;
const oggettoMatch = rispostaText.match(/^OGGETTO:\s*(.+)$/m);
if (oggettoMatch) {
  oggettoRisposta = oggettoMatch[1].trim();
  rispostaText = rispostaText.replace(/^OGGETTO:\s*.+$/m, '').trim();
}

// Controlla se Claude ha segnalato necessita di intervento umano
const needsHuman = rispostaText.includes('[ESCALATION]') || 
                   rispostaText.includes('[INTERVENTO UMANO]');

if (needsHuman) {
  rispostaText = rispostaText
    .replace('[ESCALATION]', '')
    .replace('[INTERVENTO UMANO]', '')
    .trim();
}

// Converti in HTML per Outlook
const rispostaHtml = rispostaText
  .replace(/\n\n/g, '</p><p>')
  .replace(/\n/g, '<br>')
  .replace(/^/, '<p>')
  .replace(/$/, '</p>');

return [{
  json: {
    ...emailData,
    rispostaText,
    rispostaHtml,
    oggettoRisposta,
    needsHuman,
    claudeModel: claudeResponse.model || 'unknown',
    claudeTokens: claudeResponse.usage || {},
  }
}];
